import{_ as a,o as s,c as r,a6 as i,bx as t,by as n,bz as e,bA as p,bB as c,bC as d,bD as g,bE as u,bF as l,bG as h,bH as m,bI as f,bJ as b,bK as y,bL as w,bM as k,bN as S,bO as _,bP as T,bQ as v,bR as P,bS as A}from"./chunks/framework.UYVGz2W_.js";const R=JSON.parse('{"title":"Production Specific Workflow Settings","description":"","frontmatter":{},"headers":[],"relativePath":"configure-prod/index.md","filePath":"configure-prod/index.md"}'),x={name:"configure-prod/index.md"};function D(B,o,N,O,C,E){return s(),r("div",null,[...o[0]||(o[0]=[i('<h1 id="production-specific-workflow-settings" tabindex="-1">Production Specific Workflow Settings <a class="header-anchor" href="#production-specific-workflow-settings" aria-label="Permalink to “Production Specific Workflow Settings”">​</a></h1><h2 id="configure-production-specific-settings" tabindex="-1">Configure Production-Specific Settings <a class="header-anchor" href="#configure-production-specific-settings" aria-label="Permalink to “Configure Production-Specific Settings”">​</a></h2><p>From the <strong>Navigation Menu</strong>, choose on the dropdown menu the <strong>Setting</strong>.</p><p><img src="'+t+'" alt="Drop Down menu Setting"></p><p>The first tab, <strong>Parameters</strong> allows you to change the <strong>Technical information</strong> of the production.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>If you change the <strong>FPS</strong> or <strong>Resolution</strong> after uploading previews, the changes won&#39;t be applied; you must reupload the first previews.</p></div><p><img src="'+n+'" alt="Setting Parameters"></p><p>Here, you can enable specific options for the production as</p><ul><li><p>Isolate Client Comments (Not Visible To Each Other)</p></li><li><p>Allow Artists To Download Previews</p></li><li><p>Set New Preview As Entity Thumbnail Automatically</p></li></ul><p>You can also specify the <strong>Maximum Number of Retakes</strong> for this production.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You can also change the avatar of the production on the <strong>Parameters</strong> tab.</p></div><h2 id="task-statuses" tabindex="-1">Task Statuses <a class="header-anchor" href="#task-statuses" aria-label="Permalink to “Task Statuses”">​</a></h2><h3 id="configuring-specific-task-types-for-a-production" tabindex="-1">Configuring Specific Task Types for a Production <a class="header-anchor" href="#configuring-specific-task-types-for-a-production" aria-label="Permalink to “Configuring Specific Task Types for a Production”">​</a></h3><p>On the <strong>Navigation Menu</strong>, choose on the dropdown menu the <strong>Setting</strong>.</p><p><img src="'+t+'" alt="Drop Down menu Setting"></p><p>Per default, Kitsu will load the <strong>Task Status</strong> you have defined when creating the production.</p><p>However, you can add or remove specific statuses during production if they are created on the Global Library first.</p><p><img src="'+e+'" alt="Setting status new"></p><p>On the <strong>Task Status</strong> tab, you can choose which <strong>status</strong> you want to add or remove on this production, validate your choice with the <strong>add</strong> button.</p><p><img src="'+p+'" alt="Setting Add Status"></p><h2 id="task-types" tabindex="-1">Task Types <a class="header-anchor" href="#task-types" aria-label="Permalink to “Task Types”">​</a></h2><h3 id="enabling-specific-task-types-for-a-production" tabindex="-1">Enabling Specific Task Types for a Production <a class="header-anchor" href="#enabling-specific-task-types-for-a-production" aria-label="Permalink to “Enabling Specific Task Types for a Production”">​</a></h3><p>On the <strong>Navigation Menu</strong>, choose on the dropdown menu the <strong>Setting</strong>.</p><p><img src="'+t+'" alt="Drop Down menu Setting"></p><p>By default, Kitsu will add the <strong>Task Types</strong> you have chosen when creating the production.</p><p><img src="'+c+'" alt="Setting Task Type new"></p><p>However, you can add or remove specific <strong>Task Types</strong> if they are created on the Global Library first.</p><p>For example, you can import the task workflow from another production in your library.</p><p><img src="'+d+'" alt="Setting Add Task Type"></p><p>On the <strong>Task Types</strong> tab, you can choose which production or task type you want to import  or remove on this production, validate your choice with the <strong>Import</strong> button.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>If you had a new task type <strong>AFTER</strong> creating an asset or shot, here is the <strong>DELIVERY</strong> task type.</p><p><img src="'+g+'" alt="Setting Task Type add"></p><p>You need to <strong>add this task type</strong> on the global page.</p><p><img src="'+u+'" alt="Add Task Type Global"></p><p>A pop-in will appear, and you must select the new task type on the dropdown menu.</p><p><img src="'+l+'" alt="Add Task Type Global"></p><p>Validate with <strong>Confirm</strong>.</p><p><img src="'+h+'" alt="Add Task Type example"></p></div><h2 id="asset-types" tabindex="-1">Asset Types <a class="header-anchor" href="#asset-types" aria-label="Permalink to “Asset Types”">​</a></h2><h3 id="enabling-specific-asset-types-for-a-production" tabindex="-1">Enabling Specific Asset Types for a Production <a class="header-anchor" href="#enabling-specific-asset-types-for-a-production" aria-label="Permalink to “Enabling Specific Asset Types for a Production”">​</a></h3><p>On the <strong>Navigation Menu</strong>, choose on the dropdown menu the <strong>Setting</strong>.</p><p><img src="'+t+'" alt="Drop Down menu Setting"></p><p>Per default, Kitsu will load the <strong>Asset Types</strong> you have defined when creating the production.</p><p>However, you can add or remove specific Asset Types if they are created on the Global Library first.</p><p><img src="'+m+'" alt="Setting Asset type new"></p><p>On the <strong>Asset Types</strong> tab, you can choose which <strong>Asset Types</strong> you want to add or remove on this production, validate your choice with the <strong>add</strong> button.</p><p><img src="'+f+'" alt="Setting Add Asset"></p><h2 id="status-automation" tabindex="-1">Status Automation <a class="header-anchor" href="#status-automation" aria-label="Permalink to “Status Automation”">​</a></h2><h3 id="configuring-status-automation-for-a-production" tabindex="-1">Configuring Status Automation for a Production <a class="header-anchor" href="#configuring-status-automation-for-a-production" aria-label="Permalink to “Configuring Status Automation for a Production”">​</a></h3><p>On the <strong>Navigation Menu</strong>, choose on the dropdown menu the <strong>Setting</strong>.</p><p><img src="'+t+'" alt="Drop Down menu Setting"></p><p>Per default, Kitsu will load no <strong>status automation</strong> of your status automation <strong>Global Library</strong> into your <strong>Production Library</strong>.</p><p><img src="'+b+'" alt="Setting Task Type new"></p><p>But you can use only specific <strong>Status Automation</strong>, depending on your production type.</p><p>On the <strong>Status Automation</strong> tab, you can choose which automation you want to use on this production, validate your choice with the <strong>add</strong> button.</p><p><img src="'+y+'" alt="Setting Add Task Type"></p><h2 id="preview-backgrounds" tabindex="-1">Preview Backgrounds <a class="header-anchor" href="#preview-backgrounds" aria-label="Permalink to “Preview Backgrounds”">​</a></h2><h3 id="select-specific-preview-background-for-a-production" tabindex="-1">Select Specific Preview Background for a Production <a class="header-anchor" href="#select-specific-preview-background-for-a-production" aria-label="Permalink to “Select Specific Preview Background for a Production”">​</a></h3><p>On the <strong>Navigation Menu</strong>, choose on the dropdown menu the <strong>Setting</strong>.</p><p><img src="'+t+'" alt="Drop Down menu Setting"></p><p>On the <strong>Preview Backgrounds</strong> tab, you can choose which HDR file you want to add or remove on this production,</p><p><img src="'+w+'" alt="Setting Status automation new"></p><p>Validate your choice with the <strong>add</strong> button.</p><p><img src="'+k+'" alt="Setting Add Asset"></p><p>You can review your 3D file with an HDR background.</p><p><img src="'+S+'" alt="Preview background example"></p><h2 id="artist-board" tabindex="-1">Artist Board <a class="header-anchor" href="#artist-board" aria-label="Permalink to “Artist Board”">​</a></h2><h3 id="artist-board-status-configuration" tabindex="-1">Artist Board Status Configuration <a class="header-anchor" href="#artist-board-status-configuration" aria-label="Permalink to “Artist Board Status Configuration”">​</a></h3><p>On the <strong>Navigation Menu</strong>, choose on the dropdown menu the <strong>Setting</strong>.</p><p>On the <strong>Task Status</strong> tab, you can reorder the status for the <strong>Board</strong> view.</p><p><img src="'+e+'" alt="Setting status new"></p><p><img src="'+_+'" alt="Setting status order"></p><p>Once it&#39;s done, go to the <strong>Board Status</strong> tab.</p><p><img src="'+T+'" alt="Setting board status order"></p><p>Here, you can choose who can see which status on the <strong>Board view</strong></p><p>If you don&#39;t select the status properly, it can be overwhelming for the artists if they have too much choice.</p><p><img src="'+v+'" alt="Board status bad example"></p><p>Selecting the <strong>Status</strong> properly will make it easier for the artists.</p><p><img src="'+P+'" alt="Setting board status order"></p><p><img src="'+A+'" alt="Board status good example"></p>',73)])])}const G=a(x,[["render",D]]);export{R as __pageData,G as default};
